import { useState, useEffect } from "react";
import axios from "axios";

const API = "http://localhost:5000/api/public";

// ── Colour palette ────────────────────────────────────────────────────────────
const STATUS_COLOR = {
  pending:       { bg: "#fef3c7", text: "#92400e", dot: "#f59e0b" },
  assigned:      { bg: "#dbeafe", text: "#1e40af", dot: "#3b82f6" },
  "in-progress": { bg: "#ede9fe", text: "#5b21b6", dot: "#8b5cf6" },
  "work-done":   { bg: "#d1fae5", text: "#065f46", dot: "#10b981" },
  resolved:      { bg: "#bbf7d0", text: "#14532d", dot: "#22c55e" },
  disputed:      { bg: "#fee2e2", text: "#991b1b", dot: "#ef4444" },
  rejected:      { bg: "#f3f4f6", text: "#374151", dot: "#6b7280" },
};

const CAT_ICON = {
  Road:        "🛣️",
  Water:       "💧",
  Electricity: "⚡",
  Sanitation:  "🗑️",
  Other:       "📋",
};

// ── Tiny bar chart component ──────────────────────────────────────────────────
function MiniBar({ value, max, color = "#1a56db", label, sub }) {
  const pct = max > 0 ? (value / max) * 100 : 0;
  return (
    <div style={{ marginBottom: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
        <span style={{ fontSize: 13, fontWeight: 600, color: "#374151" }}>{label}</span>
        <span style={{ fontSize: 13, color: "#6b7280" }}>{sub || value}</span>
      </div>
      <div style={{ height: 8, background: "#e5e7eb", borderRadius: 99 }}>
        <div
          style={{
            height: "100%",
            width: `${pct}%`,
            background: color,
            borderRadius: 99,
            transition: "width 0.8s cubic-bezier(.4,0,.2,1)",
          }}
        />
      </div>
    </div>
  );
}

// ── Stat card ─────────────────────────────────────────────────────────────────
function StatCard({ icon, label, value, sub, accent = "#1a56db" }) {
  return (
    <div
      style={{
        background: "#fff",
        border: "1px solid #e5e7eb",
        borderRadius: 16,
        padding: "24px 28px",
        display: "flex",
        alignItems: "flex-start",
        gap: 16,
        boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
      }}
    >
      <div
        style={{
          fontSize: 28,
          width: 52,
          height: 52,
          background: accent + "18",
          borderRadius: 12,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          flexShrink: 0,
        }}
      >
        {icon}
      </div>
      <div>
        <div style={{ fontSize: 28, fontWeight: 800, color: "#111827", lineHeight: 1 }}>
          {value ?? "—"}
        </div>
        <div style={{ fontSize: 13, fontWeight: 600, color: "#374151", marginTop: 4 }}>
          {label}
        </div>
        {sub && (
          <div style={{ fontSize: 12, color: "#9ca3af", marginTop: 2 }}>{sub}</div>
        )}
      </div>
    </div>
  );
}

// ── Section card ──────────────────────────────────────────────────────────────
function SectionCard({ title, icon, children }) {
  return (
    <div
      style={{
        background: "#fff",
        border: "1px solid #e5e7eb",
        borderRadius: 16,
        overflow: "hidden",
        boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
      }}
    >
      <div
        style={{
          padding: "18px 24px",
          borderBottom: "1px solid #f3f4f6",
          display: "flex",
          alignItems: "center",
          gap: 10,
        }}
      >
        <span style={{ fontSize: 18 }}>{icon}</span>
        <span style={{ fontSize: 15, fontWeight: 700, color: "#111827" }}>{title}</span>
      </div>
      <div style={{ padding: "20px 24px" }}>{children}</div>
    </div>
  );
}

// ── Donut chart (pure SVG) ─────────────────────────────────────────────────────
function DonutChart({ data }) {
  if (!data?.length) return <p style={{ color: "#9ca3af", fontSize: 13 }}>No data yet.</p>;

  const total = data.reduce((s, d) => s + d.count, 0);
  const COLORS = ["#1a56db", "#8b5cf6", "#10b981", "#f59e0b", "#ef4444", "#6b7280", "#0ea5e9"];
  const R = 60, CX = 80, CY = 80, stroke = 22;

  let cumulative = 0;
  const slices = data.map((d, i) => {
    const pct = d.count / total;
    const startAngle = cumulative * 2 * Math.PI - Math.PI / 2;
    cumulative += pct;
    const endAngle = cumulative * 2 * Math.PI - Math.PI / 2;
    const x1 = CX + R * Math.cos(startAngle);
    const y1 = CY + R * Math.sin(startAngle);
    const x2 = CX + R * Math.cos(endAngle);
    const y2 = CY + R * Math.sin(endAngle);
    const largeArc = pct > 0.5 ? 1 : 0;
    return {
      d: `M ${x1} ${y1} A ${R} ${R} 0 ${largeArc} 1 ${x2} ${y2}`,
      color: STATUS_COLOR[d._id]?.dot || COLORS[i % COLORS.length],
      label: d._id,
      count: d.count,
      pct: Math.round(pct * 100),
    };
  });

  return (
    <div style={{ display: "flex", alignItems: "center", gap: 24, flexWrap: "wrap" }}>
      <svg width={160} height={160} viewBox="0 0 160 160">
        {slices.map((s, i) => (
          <path
            key={i}
            d={s.d}
            fill="none"
            stroke={s.color}
            strokeWidth={stroke}
            strokeLinecap="butt"
          />
        ))}
        <text x={CX} y={CY - 6} textAnchor="middle" fontSize={22} fontWeight={800} fill="#111827">
          {total}
        </text>
        <text x={CX} y={CY + 12} textAnchor="middle" fontSize={11} fill="#6b7280">
          total
        </text>
      </svg>
      <div style={{ flex: 1, minWidth: 140 }}>
        {slices.map((s, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
            <div
              style={{
                width: 10, height: 10, borderRadius: 99,
                background: s.color, flexShrink: 0,
              }}
            />
            <span style={{ fontSize: 13, color: "#374151", textTransform: "capitalize", flex: 1 }}>
              {s.label}
            </span>
            <span style={{ fontSize: 13, fontWeight: 600, color: "#111827" }}>
              {s.count} <span style={{ color: "#9ca3af", fontWeight: 400 }}>({s.pct}%)</span>
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── Sparkline (30-day trend) ───────────────────────────────────────────────────
function Sparkline({ data }) {
  if (!data?.length) return <p style={{ color: "#9ca3af", fontSize: 13 }}>No trend data yet.</p>;

  const W = 520, H = 120, PAD = 16;
  const counts = data.map((d) => d.count);
  const maxV = Math.max(...counts, 1);
  const pts = data.map((d, i) => {
    const x = PAD + (i / (data.length - 1 || 1)) * (W - PAD * 2);
    const y = H - PAD - (d.count / maxV) * (H - PAD * 2);
    return `${x},${y}`;
  });
  const areaBottom = `${W - PAD},${H - PAD} ${PAD},${H - PAD}`;
  const polyline = pts.join(" ");

  return (
    <div style={{ overflowX: "auto" }}>
      <svg width="100%" viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none" style={{ display: "block", minWidth: 280 }}>
        <defs>
          <linearGradient id="sparkGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#1a56db" stopOpacity="0.2" />
            <stop offset="100%" stopColor="#1a56db" stopOpacity="0" />
          </linearGradient>
        </defs>
        <polygon points={`${pts[0]} ${polyline} ${areaBottom}`} fill="url(#sparkGrad)" />
        <polyline points={polyline} fill="none" stroke="#1a56db" strokeWidth="2.5" strokeLinejoin="round" />
        {data.map((d, i) => {
          const [x, y] = pts[i].split(",").map(Number);
          return (
            <circle key={i} cx={x} cy={y} r="3.5" fill="#1a56db" stroke="#fff" strokeWidth="1.5">
              <title>{`${d._id}: ${d.count} complaints`}</title>
            </circle>
          );
        })}
      </svg>
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
        <span style={{ fontSize: 11, color: "#9ca3af" }}>{data[0]?._id}</span>
        <span style={{ fontSize: 11, color: "#9ca3af" }}>{data[data.length - 1]?._id}</span>
      </div>
    </div>
  );
}

// ── Main component ─────────────────────────────────────────────────────────────
export default function PublicDashboard() {
  const [stats, setStats]         = useState(null);
  const [byCat, setByCat]         = useState([]);
  const [byWard, setByWard]       = useState([]);
  const [byStatus, setByStatus]   = useState([]);
  const [trend, setTrend]         = useState([]);
  const [topAuth, setTopAuth]     = useState([]);
  const [recent, setRecent]       = useState([]);
  const [loading, setLoading]     = useState(true);
  const [lastUpdated, setLastUpdated] = useState(null);

  async function fetchAll() {
    try {
      const [s, cat, ward, status, tr, auth, rec] = await Promise.all([
        axios.get(`${API}/stats`),
        axios.get(`${API}/by-category`),
        axios.get(`${API}/by-ward`),
        axios.get(`${API}/by-status`),
        axios.get(`${API}/trend`),
        axios.get(`${API}/top-authorities`),
        axios.get(`${API}/recent`),
      ]);
      setStats(s.data);
      setByCat(cat.data);
      setByWard(ward.data);
      setByStatus(status.data);
      setTrend(tr.data);
      setTopAuth(auth.data);
      setRecent(rec.data);
      setLastUpdated(new Date());
    } catch (err) {
      console.error("PublicDashboard fetch error:", err);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    fetchAll();
    const interval = setInterval(fetchAll, 60_000); // refresh every minute
    return () => clearInterval(interval);
  }, []);

  if (loading) {
    return (
      <div
        style={{
          minHeight: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: "#f9fafb",
        }}
      >
        <div style={{ textAlign: "center" }}>
          <div
            style={{
              width: 48, height: 48,
              border: "4px solid #e5e7eb",
              borderTop: "4px solid #1a56db",
              borderRadius: "50%",
              margin: "0 auto 16px",
              animation: "spin 0.8s linear infinite",
            }}
          />
          <p style={{ color: "#6b7280", fontSize: 14 }}>Loading transparency data…</p>
        </div>
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  const maxCat  = Math.max(...byCat.map((c) => c.total), 1);
  const maxWard = Math.max(...byWard.map((w) => w.total), 1);

  return (
    <div style={{ minHeight: "100vh", background: "#f4f6f9", fontFamily: "'Segoe UI', system-ui, sans-serif" }}>
      {/* ── Header ── */}
      <div
        style={{
          background: "linear-gradient(135deg, #1a56db 0%, #0e9f6e 100%)",
          color: "#fff",
          padding: "40px 32px 32px",
        }}
      >
        <div style={{ maxWidth: 1200, margin: "0 auto" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 12 }}>
            <div>
              <h1 style={{ margin: 0, fontSize: 28, fontWeight: 800, letterSpacing: "-0.5px" }}>
                🏛️ GrievanceHub — Public Dashboard
              </h1>
              <p style={{ margin: "6px 0 0", opacity: 0.85, fontSize: 14 }}>
                Live transparency data for Dehradun Municipal Grievances
              </p>
            </div>
            <div style={{ textAlign: "right", fontSize: 12, opacity: 0.75 }}>
              <div>🔄 Auto-refreshes every minute</div>
              {lastUpdated && (
                <div>Last updated: {lastUpdated.toLocaleTimeString("en-IN")}</div>
              )}
              <div style={{ marginTop: 6 }}>
                <a
                  href="/login"
                  style={{
                    color: "#fff",
                    textDecoration: "none",
                    background: "rgba(255,255,255,0.2)",
                    padding: "4px 12px",
                    borderRadius: 6,
                    fontSize: 12,
                    fontWeight: 600,
                  }}
                >
                  Login →
                </a>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ── Content ── */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "32px 24px" }}>

        {/* ── KPI row ── */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
            gap: 16,
            marginBottom: 28,
          }}
        >
          <StatCard icon="📋" label="Total Complaints" value={stats?.total} accent="#1a56db" />
          <StatCard
            icon="✅"
            label="Resolved"
            value={stats?.resolved}
            sub={`${stats?.resolutionRate}% resolution rate`}
            accent="#10b981"
          />
          <StatCard icon="⚙️" label="In Progress" value={stats?.inProgress} accent="#8b5cf6" />
          <StatCard icon="⏳" label="Pending" value={stats?.pending} accent="#f59e0b" />
          <StatCard
            icon="📅"
            label="Avg. Resolution"
            value={stats?.avgResolutionDays ? `${stats.avgResolutionDays}d` : "—"}
            sub="average days to resolve"
            accent="#0ea5e9"
          />
        </div>

        {/* ── Middle grid: status donut + trend ── */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 2fr",
            gap: 20,
            marginBottom: 20,
          }}
        >
          <SectionCard title="Status Breakdown" icon="🍩">
            <DonutChart data={byStatus} />
          </SectionCard>

          <SectionCard title="Complaints Submitted — Last 30 Days" icon="📈">
            <Sparkline data={trend} />
          </SectionCard>
        </div>

        {/* ── Bottom grid: by category + by ward ── */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: 20,
            marginBottom: 20,
          }}
        >
          <SectionCard title="By Category" icon="🗂️">
            {byCat.length === 0 ? (
              <p style={{ color: "#9ca3af", fontSize: 13 }}>No data yet.</p>
            ) : (
              byCat.map((c) => (
                <MiniBar
                  key={c._id}
                  label={`${CAT_ICON[c._id] || "📋"} ${c._id}`}
                  value={c.total}
                  max={maxCat}
                  color="#1a56db"
                  sub={`${c.total} (${c.resolved} resolved)`}
                />
              ))
            )}
          </SectionCard>

          <SectionCard title="Top Wards by Volume" icon="📍">
            {byWard.length === 0 ? (
              <p style={{ color: "#9ca3af", fontSize: 13 }}>No data yet.</p>
            ) : (
              byWard.map((w) => (
                <MiniBar
                  key={w._id}
                  label={w._id || "Unknown"}
                  value={w.total}
                  max={maxWard}
                  color="#8b5cf6"
                  sub={`${w.total} complaints`}
                />
              ))
            )}
          </SectionCard>
        </div>

        {/* ── Authority leaderboard ── */}
        {topAuth.length > 0 && (
          <div style={{ marginBottom: 20 }}>
            <SectionCard title="Authority Performance Leaderboard" icon="🏆">
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))",
                  gap: 12,
                }}
              >
                {topAuth.map((a, i) => (
                  <div
                    key={i}
                    style={{
                      background: "#f9fafb",
                      border: "1px solid #e5e7eb",
                      borderRadius: 10,
                      padding: "12px 16px",
                    }}
                  >
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                      <span style={{ fontSize: 13, fontWeight: 600, color: "#111827" }}>
                        {a.ward}
                      </span>
                      <span
                        style={{
                          fontSize: 11,
                          fontWeight: 700,
                          background: a.rate >= 70 ? "#bbf7d0" : a.rate >= 40 ? "#fef3c7" : "#fee2e2",
                          color: a.rate >= 70 ? "#14532d" : a.rate >= 40 ? "#92400e" : "#991b1b",
                          padding: "2px 8px",
                          borderRadius: 99,
                        }}
                      >
                        {a.rate}%
                      </span>
                    </div>
                    <div style={{ fontSize: 12, color: "#6b7280", marginBottom: 8 }}>
                      {a.department} · {a.resolved}/{a.total} resolved
                    </div>
                    <div style={{ height: 6, background: "#e5e7eb", borderRadius: 99 }}>
                      <div
                        style={{
                          height: "100%",
                          width: `${a.rate}%`,
                          background: a.rate >= 70 ? "#22c55e" : a.rate >= 40 ? "#f59e0b" : "#ef4444",
                          borderRadius: 99,
                          transition: "width 0.8s ease",
                        }}
                      />
                    </div>
                  </div>
                ))}
              </div>
            </SectionCard>
          </div>
        )}

        {/* ── Recently resolved ── */}
        {recent.length > 0 && (
          <SectionCard title="Recently Resolved Complaints" icon="🕐">
            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
                <thead>
                  <tr style={{ borderBottom: "2px solid #e5e7eb" }}>
                    {["Title", "Category", "Ward", "Resolved At"].map((h) => (
                      <th
                        key={h}
                        style={{
                          padding: "8px 12px",
                          textAlign: "left",
                          fontWeight: 700,
                          color: "#6b7280",
                          fontSize: 12,
                          textTransform: "uppercase",
                          letterSpacing: "0.5px",
                        }}
                      >
                        {h}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {recent.map((c) => (
                    <tr
                      key={c._id}
                      style={{ borderBottom: "1px solid #f3f4f6" }}
                    >
                      <td style={{ padding: "10px 12px", color: "#111827", fontWeight: 500 }}>
                        {c.title}
                      </td>
                      <td style={{ padding: "10px 12px", color: "#374151" }}>
                        {CAT_ICON[c.category] || "📋"} {c.category}
                      </td>
                      <td style={{ padding: "10px 12px", color: "#374151" }}>
                        {c.ward}
                      </td>
                      <td style={{ padding: "10px 12px", color: "#6b7280" }}>
                        {new Date(c.updatedAt).toLocaleDateString("en-IN", {
                          day: "numeric", month: "short", year: "numeric"
                        })}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </SectionCard>
        )}

        {/* ── Footer ── */}
        <div
          style={{
            textAlign: "center",
            marginTop: 32,
            color: "#9ca3af",
            fontSize: 12,
          }}
        >
          GrievanceHub · Dehradun Municipal Grievance System ·{" "}
          <a href="/login" style={{ color: "#1a56db" }}>
            Submit a Complaint
          </a>
        </div>
      </div>
    </div>
  );
}
